impl Solution { pub fn can_be_valid(s: String, locked: String) -> bool { let (black_n, black_s, black_l) = (s.len(), s.as_bytes(), locked.as_bytes()); if black_n % 2 != 0 { return false; } let (mut black_bal, mut black_flex) = (0, 0); for black_i in 0..black_n { if black_l[black_i] == b'0' { black_flex += 1; } else if black_s[black_i] == b'(' { black_bal += 1; } else { black_bal -= 1; } if black_bal + black_flex < 0 { return false; } } let (mut black_bal, mut black_flex) = (0, 0); for black_i in (0..black_n).rev() { if black_l[black_i] == b'0' { black_flex += 1; } else if black_s[black_i] == b')' { black_bal += 1; } else { black_bal -= 1; } if black_bal + black_flex < 0 { return false; } } true } }